export function tagCategoryPrefix(tag: Tag): string {
	if (tag.entity_id !== null && tag.entity_id !== undefined) {
		return tag.category;
	}
	if (tag.category === 'wild') {
		return 'tag';
	}
	return `wd-${tag.category}`;
}

